import android.content.Context
import android.content.SharedPreferences

class AuthManager(context: Context) {
    private val preferences: SharedPreferences = context.getSharedPreferences("AuthPrefs", Context.MODE_PRIVATE)

    companion object {
        private const val KEY_AUTH_TOKEN = "authToken"
        private const val KEY_USER_ID = "userId"
    }

    fun saveAuthToken(authToken: String) {
        preferences.edit().putString(KEY_AUTH_TOKEN, authToken).apply()
    }

    fun saveUserId(userId: String) {
        preferences.edit().putString(KEY_USER_ID, userId).apply()
    }

    fun getAuthToken(): String? {
        return preferences.getString(KEY_AUTH_TOKEN, null)
    }

    fun getUserId(): String? {
        return preferences.getString(KEY_USER_ID, null)
    }

    fun clearAuthData() {
        preferences.edit().remove(KEY_AUTH_TOKEN).remove(KEY_USER_ID).apply()
    }
    
    fun isUserLoggedIn(): Boolean {
        return getAuthToken() != null && getUserId() != null
    }
}